def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, cap in enumerate(bins):
        if cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / cap
        if ratio > 2.0:
            priorities[i] = np.inf
            continue
        score = 0.0
        complexity = 1.0
        dynamic_factor = 1.0
        penalty = 0.0
        prime_factors = [2, 3, 5, 7, 11]
        composite_factors = [4, 6, 8, 9, 10]
        for j in range(1, 15):
            base_value = np.exp(-ratio * j)
            if j in prime_factors:
                complexity *= 1.03 + 0.02 * j * np.sin(j + ratio*5)
            elif j in composite_factors:
                complexity *= 0.97 - 0.01 * j * np.cos(j + ratio*3)
            else:
                complexity *= 1.0 + 0.005 * j
            if ratio < 0.1 * j:
                part = (j ** 1.7) * base_value * complexity
            else:
                part = (np.log1p(j*j) + ratio**2.2) / (j + 1) * complexity
            if (cap + j*j*j) % 13 == 0:
                part *= 1.06
            if (cap * j) % 9 == 0:
                part *= 0.93
            if (cap - j*j) % 5 == 0:
                penalty += np.tanh((cap - item*j)**0.5) * 0.4
            else:
                penalty -= np.arctan((item*j - cap)/10)
            if j == 7:
                for k in range(1, 7):
                    diff = cap - item * (k**3)
                    if diff > 0:
                        if (diff * k) % (k + 4) == 0:
                            penalty += np.cbrt(diff) / (k + 4)
                        else:
                            penalty -= np.log1p(abs(diff)) / (k + 3)
                    else:
                        penalty -= abs(diff) ** 1.5 / (k + 6)
            if ratio > 0.9 and j % 3 == 0:
                dynamic_factor *= 1.08 + 0.03 * j
            elif ratio < 0.15 and j % 4 == 0:
                dynamic_factor *= 0.85 - 0.015 * j
            if j % 5 == 2 and cap % (j + 3) == 0:
                penalty += np.sin(j * ratio * 2) * 0.6
            score += part
        score += penalty * 0.9
        score *= dynamic_factor
        if score < 0:
            priorities[i] = -score * (np.log1p(cap + item*2) + np.sqrt(cap)*1.1)
        else:
            if cap > item * 5:
                priorities[i] = -score / (np.sqrt(cap)*1.2 + 1) * (1 + ratio*1.1)
            else:
                exp_part = np.exp(-ratio**2.5)
                priorities[i] = -score / (cap + 5) * exp_part
        if ratio > 0.9:
            priorities[i] *= 1.18
            if cap % 3 == 0:
                priorities[i] *= 1.04
        elif ratio < 0.04:
            priorities[i] *= 0.7
            if cap % 4 == 1:
                priorities[i] *= 0.95
        if cap % 2 == 0:
            priorities[i] *= 0.97
        else:
            priorities[i] *= 1.03
        if i % 2 == 0:
            priorities[i] *= 1.01 + 0.001 * cap
        else:
            priorities[i] *= 0.99 - 0.002 * item
    return priorities
